const testNameMapping = {};
seedTests.forEach(t => { testNameMapping[t.name.toLowerCase()] = t; });

const packageList = packages.map(pkg => ({
  ...pkg,
  testsIncluded: pkg.testsIncluded.filter(n => testNameMapping[n.toLowerCase()]),
  slug: pkg.id,
}));

function getPackageBySlug(slug) {
  return packageList.find(p => p.id === slug || p.slug === slug) || null;
}

function makeSlug(name) {
  return name.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '');
}

export { packageList, getPackageBySlug, makeSlug };